mapper.select:
SELECT p.POST_ID, p.POST_TITLE, p.POST_IMG, p.POST_RATING, p.POST_CREATED_AT, m.MEMBER_NAME, pl.PLACE_NAME, (SELECT COUNT(*) FROM POST_LIKE lk WHERE lk.POST_ID = p.POST_ID) AS LIKE_COUNT, (SELECT COUNT(*) FROM COMMENT c WHERE c.POST_ID = p.POST_ID) AS COMMENT_COUNT FROM POST p JOIN MEMBER m ON p.member_id = m.member_id JOIN PLACE pl on p.PLACE_ID = pl.PLACE_ID
WHERE p.POST_TITLE LIKE CONCAT('%', #{keyword}, '%') OR p.POST_CONTENT LIKE CONCAT('%', #{keyword}, '%')
ORDER BY p.POST_ID DESC LIMIT #{size} OFFSET #{offset}
